def oauth_consumer_strategies do
  [:auth, :oauth_consumer_strategies]
  |> get([])
  |> Enum.map(fn strategy ->
    case strategy do
      {id, label} when is_atom(id) -> %{id: id, label: label}
      id when is_atom(id) -> %{id: id, label: nil}
    end
  end)
end

