definition:
def create_cache("actor_" <> name) do
  case fetch_actor_event_feed(name) do
    {:ok, res} -> {:commit, res}
    {:error, err} -> {:ignore, err}
  end
end
def create_cache("token_" <> token) do
  case fetch_events_from_token(token) do
    {:ok, res} -> {:commit, res}
    {:error, err} -> {:ignore, err}
  end
end
def create_cache("instance") do
  {:ok, res} = fetch_instance_feed()
  {:commit, res}
end

def fetch_actor_event_feed(name, limit \\ @item_limit) do
  case Common.fetch_actor_event_feed(name, limit) do
    {:ok, actor, events, posts} -> {:ok, build_actor_feed(actor, events, posts)}
    {:error, err} -> {:error, err}
  end
end

def export_public_actor(name, limit \\ @item_limit) do
  case Common.fetch_actor_event_feed(name, limit) do
    {:ok, _actor, events, _posts} -> {:ok, events_to_ics(events)}
    {:error, err} -> {:error, err}
  end
end

def fetch_events_from_token(token, limit \\ @item_limit) do
  case Common.fetch_events_from_token(token, limit) do
    %{events: events} -> {:ok, events_to_ics(events)}
    {:error, err} -> {:error, err}
  end
end

def load_config(provider, acc) do
  acc ++
    [
      %{
        id: provider.id(),
        enabled: provider.enabled?(),
        configuration: convert_config(provider.configuration())
      }
    ]
end

def commit do
  @commit
end

def maybe_parse(html) do
  Enum.reduce_while(parsers(), %{}, fn parser, acc ->
    Logger.debug("Using #{inspect(parser)} to parse link")

    case parser.parse(html, acc) do
      {:ok, data} -> {:halt, data}
      {:error, _msg} -> {:cont, acc}
    end
  end)
end

